266→		{
267→			Pair.Value->Destroy();
268→		}
269→	}
270→	EdgeMap.Empty();
271→
272→	// 再销毁节点
273→	for (auto& Pair : NodeMap)
274→	{
275→		if (Pair.Value)
276→		{
277→			Pair.Value->Destroy();
278→		}
279→	}
280→	NodeMap.Empty();
281→
282→	AdjacencyList.Empty();
283→	NodeEdgeIndex.Empty();
284→	NextNodeID = 0;
285→}
