344→bool ALFPWorldMapManager::SaveNodesToCSV(const FString& FilePath)
345→{
346→	// CSV 头部（UE DataTable 格式）
347→	FString CSVContent = TEXT("---,NodeID,PosX,PosY,NodeType,BattleMapName,StarRating,bCanEscape,EventID,PrerequisiteNodeIDs\n");
348→
349→	for (const auto& Pair : NodeMap)
350→	{
351→		ALFPWorldMapNode* Node = Pair.Value;
352→		if (!Node) continue;
353→
354→		FLFPWorldNodeRow Row = Node->ExportToRowData();
355→		FString RowName = FString::FromInt(Row.NodeID);
356→
357→		// 节点类型枚举名
358→		FString NodeTypeStr = UEnum::GetValueAsString(Row.NodeType);
359→		NodeTypeStr = NodeTypeStr.RightChop(NodeTypeStr.Find(TEXT("::")) + 2);
360→
361→		CSVContent += FString::Printf(TEXT("%s,%d,%f,%f,%s,%s,%d,%s,%s,%s\n"),
362→			*RowName,
363→			Row.NodeID,
364→			Row.PosX,
365→			Row.PosY,
366→			*NodeTypeStr,
367→			*Row.BattleMapName,
368→			Row.StarRating,
369→			Row.bCanEscape ? TEXT("True") : TEXT("False"),
370→			*Row.EventID,
371→			*Row.PrerequisiteNodeIDs);
372→	}
373→
374→	// 确保目录存在
375→	FString Directory = FPaths::GetPath(FilePath);
376→	if (!FPaths::DirectoryExists(Directory))
377→	{
378→		IFileManager::Get().MakeDirectory(*Directory, true);
379→	}
380→
381→	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *FilePath,
382→		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
383→
384→	if (bSuccess)
385→	{
386→		UE_LOG(LogTemp, Log, TEXT("SaveNodesToCSV: 保存 %d 个节点到 %s"), NodeMap.Num(), *FilePath);
387→	}
388→	else
389→	{
390→		UE_LOG(LogTemp, Error, TEXT("SaveNodesToCSV: 保存失败 %s"), *FilePath);
391→	}
392→	return bSuccess;
393→}
