 42→	// 场景切换淡入效果
 43→	if (PlayerCameraManager)
 44→	{
 45→		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 46→		float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 47→		PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 48→	}
 49→
 50→	// 首帧跳过相机平滑插值
 51→	bSnapCameraNextFrame = true;
 52→}
 53→
 54→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 55→{
 56→	Super::Tick(DeltaTime);
 57→
 58→	if (bIsDragging)
 59→	{
 60→		DragTime += DeltaTime;
 61→	}
 62→
 63→	// 更新相机位置和旋转
 64→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 65→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 66→
 67→	// 相机旋转：俯视角
 68→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 69→
 70→	// 平滑插值并设置
 71→	FRotator CurrentRotation = GetControlRotation();
 72→	if (bSnapCameraNextFrame)
 73→	{
 74→		SetControlRotation(TargetRotation);
 75→	}
 76→	else
 77→	{
 78→		SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 79→	}
 80→
 81→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 82→	if (APawn* ControlledPawn = GetPawn())
 83→	{
 84→		if (bSnapCameraNextFrame)
 85→		{
 86→			// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 87→			ControlledPawn->SetActorLocation(TargetLocation);
 88→			bSnapCameraNextFrame = false;
 89→		}
 90→		else
 91→		{
 92→			FVector CurrentLocation = ControlledPawn->GetActorLocation();
 93→			ControlledPawn->SetActorLocation(
 94→				FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 95→			);
 96→		}
 97→	}
 98→}
