122→// ============== 输入处理 ==============
123→
124→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
125→{
126→	bIsDragging = false;
127→	if (DragTime > DragThresholdTime)
128→	{
129→		DragTime = 0.f;
130→		return;
131→	}
132→	DragTime = 0.f;
133→
134→	// 编辑器模式优先处理
135→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
136→	{
137→		// 射线检测点击的节点
138→		FHitResult HitResult;
139→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
140→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
141→
142→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
143→
144→		switch (CurrentTool)
145→		{
146→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
147→			{
148→				// 射线投射到 Z=0 平面获取世界坐标
149→				FVector WorldOrigin, WorldDirection;
150→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
151→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
152→				{
153→					float T = -WorldOrigin.Z / WorldDirection.Z;
154→					FVector HitPoint = WorldOrigin + WorldDirection * T;
155→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
156→				}
157→			}
158→			break;
159→
160→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
161→			if (ClickedNode)
162→			{
163→				WorldMapEditorComponent->SelectNode(ClickedNode);
164→				WorldMapEditorComponent->RemoveSelectedNode();
165→			}
166→			break;
167→
168→		case ELFPWorldMapEditorTool::WMET_MoveNode:
169→			if (ClickedNode)
170→			{
171→				WorldMapEditorComponent->SelectNode(ClickedNode);
172→			}
173→			else if (WorldMapEditorComponent->GetSelectedNode())
174→			{
175→				// 移动到点击位置
176→				FVector WorldOrigin, WorldDirection;
177→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
178→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
179→				{
180→					float T = -WorldOrigin.Z / WorldDirection.Z;
181→					FVector HitPoint = WorldOrigin + WorldDirection * T;
182→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
183→				}
184→			}
185→			break;
186→
187→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
188→			if (ClickedNode)
189→			{
190→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
191→			}
192→			break;
193→
194→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
195→			if (ClickedNode)
196→			{
197→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
198→			}
199→			break;
200→
201→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
202→			if (ClickedNode)
203→			{
204→				WorldMapEditorComponent->SelectNode(ClickedNode);
205→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
206→			}
207→			break;
208→
209→		default:
210→			break;
211→		}
212→		return;
213→	}
214→
215→	// 游戏模式：棋子移动中屏蔽点击
216→	ALFPWorldMapManager* Manager = GetWorldMapManager();
217→	if (Manager && Manager->IsPawnMoving()) return;
218→
219→	// 游戏模式：点击节点移动或进入
220→	FHitResult HitResult;
221→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
222→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
223→
224→	if (ClickedNode)
225→	{
226→		if (!Manager || !Manager->GetPlayerState()) return;
227→
228→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
229→
230→		// 点击当前节点 → 进入节点
231→		if (ClickedNode->NodeID == CurrentNodeID)
232→		{
233→			EnterNode(ClickedNode);
234→			return;
235→		}
236→
237→		// 点击相邻可达节点 → 移动
238→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
239→		if (ReachableIDs.Contains(ClickedNode->NodeID))
240→		{
241→			MoveToNode(ClickedNode);
242→		}
243→		else
244→		{
245→			// 不可达，只选中
246→			SelectNode(ClickedNode);
247→		}
248→	}
249→}
