312→void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
313→{
314→	if (!bIsDragging) return;
315→
316→	FVector2D CurrentMousePos;
317→	GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
318→	FVector2D Delta = CurrentMousePos - DragStartPosition;
319→
320→	CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
321→	DragStartPosition = CurrentMousePos;
