361→void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
362→{
363→	if (!Node) return;
364→
365→	ALFPWorldMapManager* Manager = GetWorldMapManager();
366→	if (!Manager) return;
367→
368→	// 棋子移动中不允许操作
369→	if (Manager->IsPawnMoving()) return;
370→
371→	ClearReachableHighlight();
372→
373→	// 记录目标节点，移动完成后自动进入
374→	PendingEnterNode = Node;
375→
376→	// 绑定棋子移动完成回调
377→	if (ALFPWorldMapPawn* MapPawn = Manager->GetPlayerPawn())
378→	{
379→		MapPawn->OnMoveComplete.AddUniqueDynamic(this, &ALFPWorldMapPlayerController::OnPawnMoveCompleted);
380→	}
381→
382→	bool bMoved = Manager->MovePlayer(Node->NodeID);
383→	if (!bMoved)
384→	{
385→		PendingEnterNode = nullptr;
386→	}
387→}
