389→void ALFPWorldMapPlayerController::ShowReachableNodes()
390→{
391→	ClearReachableHighlight();
392→
393→	ALFPWorldMapManager* Manager = GetWorldMapManager();
394→	if (!Manager || !Manager->GetPlayerState()) return;
395→
396→	TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
397→	for (int32 NodeID : ReachableIDs)
398→	{
399→		if (ALFPWorldMapNode* Node = Manager->GetNode(NodeID))
400→		{
401→			Node->SetHighlighted(true);
402→			ReachableNodes.Add(Node);
403→		}
404→	}
405→}
